import { NextResponse } from 'next/server';
import prisma from '@/lib/prisma';
import fs from 'fs';
import path from 'path';

export async function GET() {
    try {
        const filePath = path.join(process.cwd(), 'kurslar_backup.json');
        
        if (!fs.existsSync(filePath)) {
            return NextResponse.json({ error: "kurslar_backup.json bulunamadı!" }, { status: 404 });
        }

        const data = fs.readFileSync(filePath, 'utf-8');
        const courses = JSON.parse(data);

        let addedCount = 0;
        let skipCount = 0;

        for (const item of courses) {
            const existing = await prisma.course.findFirst({
                where: { OR: [ { slug: item.slug }, { title: item.title } ]}
            });

            if (!existing) {
                await prisma.course.create({
                    data: {
                        title: item.title,
                        slug: item.slug,
                        description: item.description,
                        price: item.price,
                        oldPrice: item.oldPrice,
                        imageUrl: item.imageUrl,
                        type: 'KURS',
                        category: item.category,
                        isActive: item.isActive,
                    }
                });
                addedCount++;
            } else {
                skipCount++;
            }
        }

        return NextResponse.json({
            message: "Import tamamlandı!",
            total_in_file: courses.length,
            added: addedCount,
            skipped_duplicates: skipCount
        });

    } catch (e: any) {
        console.error("Import Error:", e);
        return NextResponse.json({ error: e.message }, { status: 500 });
    }
}
